        int valueSum = 0;

        for (Node node : nodes) {
            valueSum += node.val;

            for (Node child : node.children) {
                valueSum -= child.val;
            }
        }

        for (Node node : nodes) {
            if (node.val == valueSum) {
                return node;
            }
        }

        return null;
    }
}
